def calculate(s):
    res, cur, sign, st = 0, 0, 1, []
    for c in s:
        if c.isdigit(): cur = cur*10 + int(c)
        elif c in '+-': res += sign*cur; cur = 0; sign = 1 if c == '+' else -1
        elif c == '(': st.append(res); st.append(sign); res = 0; sign = 1
        elif c == ')': res += sign*cur; cur = 0; res *= st.pop(); res += st.pop()
    return res + sign*cur

